<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Invoices</h1><p class="text-muted mb-0">Billing, delivery, and payment tracking.</p></div><a class="btn btn-primary" href="/portal/invoices/create"><i class="fa-solid fa-plus"></i> New Invoice</a></div><div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Invoice</th><th>Customer</th><th>Issued</th><th>Status</th><th>Total</th><th>Balance</th><th></th></tr></thead><tbody><?php foreach($invoices as $i):?><tr><td><strong><?=e($i['invoice_number'])?></strong></td><td><?=e($i['display_name'])?></td><td><?=e($i['issue_date'])?></td><td><span class="badge text-bg-<?=$i['status']==='paid'?'success':($i['status']==='overdue'?'danger':'secondary')?>"><?=e($i['status'])?></span></td><td><?=money($i['total'])?></td><td><?=money($i['balance_due'])?></td><td class="text-end"><a class="btn btn-sm btn-outline-primary" href="/portal/invoices/<?=$i['id']?>">Open</a></td></tr><?php endforeach; if(!$invoices):?><tr><td colspan="7" class="text-center py-5 text-muted">No invoices yet.</td></tr><?php endif?></tbody></table></div></div>
